import SwiftUI
struct DraggableArea: NSViewRepresentable {
    func makeNSView(context: Context) -> DraggableNSView {
        return DraggableNSView()
    }
    func updateNSView(_ nsView: DraggableNSView, context: Context) {}

    class DraggableNSView: NSView {
        override func mouseDown(with event: NSEvent) {
            if let window = AppDelegate.sharedWindow {
                window.performDrag(with: event)
            }
        }
    }
}
struct MouseDownDraggableView: NSViewRepresentable {
    func makeNSView(context: Context) -> NSView {
        let view = NSView()
        view.wantsLayer = true
        // 透明，可互動
        view.layer?.backgroundColor = NSColor.clear.cgColor
        // mouseDown callback
        view.addGestureRecognizer(NSClickGestureRecognizer(target: context.coordinator, action: #selector(Coordinator.handleClick)))
        return view
    }

    func updateNSView(_ nsView: NSView, context: Context) {}

    func makeCoordinator() -> Coordinator {
        Coordinator()
    }

    class Coordinator: NSObject {
        @objc func handleClick() {
            if let window = AppDelegate.sharedWindow {
                let mouseLocation = NSEvent.mouseLocation
                let event = NSEvent.mouseEvent(
                    with: .leftMouseDown,
                    location: mouseLocation,
                    modifierFlags: [],
                    timestamp: ProcessInfo.processInfo.systemUptime,
                    windowNumber: window.windowNumber,
                    context: nil,
                    eventNumber: 0,
                    clickCount: 1,
                    pressure: 1
                )
                if let event = event {
                    window.performDrag(with: event)
                }
            }
        }
    }
}
struct TitleBarView: View {
    var body: some View {
        ZStack {
            HStack {
                Text("Lenovo monitor firmware service tool")
                    .font(.system(size: 22, weight: .bold))
                    .foregroundColor(.white)
