            }
            DraggableArea() // 疊在最上層
        }
        .frame(height: 40)
        .background(Color(red: 0.19, green: 0.51, blue: 0.91))
        .clipped()
        // 或 .contentShape(Rectangle()) 讓整個區域可拖曳
    }
}



struct BlueOutlineButton: View {
    let title: String
    let action: () -> Void
    var body: some View {
        Button(action: action) {
            ZStack {
                RoundedRectangle(cornerRadius: 14)
                    .fill(Color(red: 0.12, green: 0.55, blue: 0.94))
                RoundedRectangle(cornerRadius: 14)
                    .stroke(Color(red: 0.21, green: 0.54, blue: 1.0), lineWidth: 4)
                Text(title)
                    .font(.system(size: 17, weight: .semibold))
                    .foregroundColor(.white)
