struct ContentView: View {
    @State private var versionOutput = "01.00"
    @State private var devices: [DeviceItem] = [
        .init(name: "USB HUB 1", comID: "HB0", asIs: "8045", toBe: "8045", status: ""),
        .init(name: "PD", comID: "PD0", asIs: "0.33", toBe: "0.33.0.0", status: ""),
        .init(name: "Scaler", comID: "SC0", asIs: "L0.7", toBe: "L0.7", status: "")
    ]

    var body: some View {
        ZStack {
            Color(.sRGB, red: 0.88, green: 0.89, blue: 0.92).ignoresSafeArea()
            VStack(spacing: 0) {
                TitleBarView()
                HStack(spacing: 0) {
                    // 左灰底寬度（更窄）
                    LeftPanelView(versionOutput: versionOutput)
                        .frame(width: 270)
                        .background(Color(.sRGB, white: 0.85, opacity: 1.0))

                    VStack(spacing: 0) {
                        RightPanelView(devices: devices)
                            .frame(maxWidth: .infinity, maxHeight: .infinity)
                        BottomButtonBar()
                            .frame(maxWidth: .infinity)
                    }
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
                    .background(Color.white)
                }

            }
            .frame(width: 1100, height: 600)
        }
    }
}






// MARK: - Left Panel

struct LeftPanelView: View {
    let versionOutput: String
    var body: some View {
        VStack(spacing: 0) {
            // 白色 General 資訊區塊
