// MARK: - Right Panel

struct RightPanelView: View {
    let devices: [DeviceItem]

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            // ATTENTION 區塊，置中
            HStack(spacing: 12) {
                Spacer()
                Image(systemName: "exclamationmark.triangle.fill")
                    .resizable()
                    .frame(width: 48, height: 48)
                    .foregroundColor(.black)
                Text("ATTENTION")
                    .font(.title2).bold()
                Spacer()
            }
            .padding(.top, 16)

            // 左對齊說明文字 & 字體加大
            Text("""
                DO NOT turn off the display or remove USB cable until monitor reboot.
                DO NOT turn off or sleep the computer during firmware update.
                """)
                .font(.system(size: 18, weight: .semibold))
                .foregroundColor(.black)
                .multilineTextAlignment(.leading)
                .frame(maxWidth: .infinity, alignment: .leading)

            // --------- 表格外框 ----------
            ZStack(alignment: .topLeading) {
                RoundedRectangle(cornerRadius: 3)
                    .stroke(Color.gray.opacity(0.38), lineWidth: 1)
                    .background(Color.white.cornerRadius(3))
                VStack(spacing: 0) {
                    // header
                    HStack(spacing: 0) {
                        TableHeaderText(text: "Com", width: 140 , color: .white) // 這裡可加寬到140
                        Divider().frame(width: 1, height: 32).background(Color.white)
                        TableHeaderText(text: "Com ID", width: 100, color: .white)
                        Divider().frame(width: 1, height: 32).background(Color.white)
                        TableHeaderText(text: "As Is", width: 100, color: .white)
                        Divider().frame(width: 1, height: 32).background(Color.white)
                        TableHeaderText(text: "To Be", width: 120, color: .white)
                        Divider().frame(width: 1, height: 32).background(Color.white)
                        TableHeaderText(text: "Updating Status", width: 180, color: .white)
                        Spacer()
                    }
                    .background(Color(.sRGB, white: 0.63, opacity: 1.0))


                    // 資料列
                    ForEach(devices) { item in
                        HStack(spacing: 0) {
                            TableCellText(text: item.name, width: 140)
                            TableCellText(text: item.comID, width: 100)
                            TableCellText(text: item.asIs, width: 100)
                            TableCellText(text: item.toBe, width: 120)
                            TableCellText(text: item.status, width: 180)
                            Spacer()
                        }
                        .frame(height: 28)
                    }
                }
            }
            // 讓表格**自動撐滿**可用空間，不用固定寬度
            .frame(maxWidth: .infinity, minHeight: 140, alignment: .leading)
            .padding(.top, 4)
            .padding(.bottom, 8)
            // --------- 表格外框結束 ----------

            Spacer()
        }
        .padding(.leading, 32)
        .padding(.trailing, 32)
        .padding(.top, 18)
        .padding(.bottom, 0)
        .background(Color.white)
    }
}

