extension Color {
    static let mac_bg        = Color(.sRGB, white: 0.98, opacity: 1.0)       // 近系統白
    static let mac_card      = Color(.sRGB, white: 1.0, opacity: 0.80)        // 淡白半透明
    static let mac_border    = Color(.sRGB, white: 0.89, opacity: 1.0)        // 蘋果灰
    static let mac_header    = Color(.sRGB, white: 0.90, opacity: 1.0)        // 面板 header
    static let mac_shadow    = Color(.sRGB, white: 0.78, opacity: 1.0)        // 陰影灰
    static let mac_blue      = Color(red: 0.13, green: 0.52, blue: 1.00)      // 蘋果藍
    static let mac_textMain  = Color(.sRGB, white: 0.13, opacity: 1.0)        // 幾乎黑
    static let mac_textGray  = Color(.sRGB, white: 0.40, opacity: 1.0)        // 灰字
    static let mac_btnGray   = Color(.sRGB, white: 0.96, opacity: 1.0)        // 按鈕灰底
    static let mac_btnStroke = Color(.sRGB, white: 0.82, opacity: 1.0)        // 按鈕灰線
}

struct TitleBarView: View {
    var body: some View {
        ZStack {
            HStack {
                Text("Lenovo monitor firmware service tool")
                    .font(.system(size: 22, weight: .bold))
                    .foregroundColor(.mac_textMain)
                    .padding(.leading, 16)
                Spacer()
            }
            DraggableArea()
        }
        .frame(height: 40)
        .background(BlurView(style: .sidebar)) // <-- 這裡重點
        .overlay(
            Rectangle()
                .frame(height: 1)
                .foregroundColor(Color.mac_border), alignment: .bottom
        )
        .clipped()
    }
}


struct BlueOutlineButton: View {
    let title: String
    let action: () -> Void
    @State private var hovering = false

    var body: some View {
        Button(action: action) {
            Text(title)
                .font(.system(size: 17, weight: .semibold))
                .foregroundColor(hovering ? .white : .mac_textMain)
                .padding(.horizontal, 36)
                .frame(height: 44)
                .background(
                    ZStack {
                        RoundedRectangle(cornerRadius: 14)
                            .fill(hovering ? Color.mac_blue : Color.mac_btnGray)
                        RoundedRectangle(cornerRadius: 14)
                            .stroke(hovering ? Color.mac_blue : Color.mac_btnStroke, lineWidth: 2)
                    }
                )
        }
        .buttonStyle(PlainButtonStyle())
        .onHover { hover in hovering = hover }
        .focusable(false)
        .animation(.easeInOut(duration: 0.16), value: hovering)
    }
}

struct TableHeaderText: View {
    let text: String
    let width: CGFloat
    var color: Color = .mac_textMain
    var body: some View {
        Text(text)
            .font(.system(size: 15, weight: .bold))
            .foregroundColor(color)
            .frame(width: width, height: 32, alignment: .leading)
            .padding(.leading, 4)
    }
}

